import React from "react";

function ItemCard({ item, onEdit, onDelete, onReportFound, canManage }) {
  const statusClass = `status-chip status-${(item.status || "").toLowerCase()}`;
  let parsedImages = [];

  try {
    parsedImages = item.referenceImages ? JSON.parse(item.referenceImages) : [];
  } catch (error) {
    parsedImages = [];
  }

  const previewImage = parsedImages[0] || item.imageUrl || "https://via.placeholder.com/600x320?text=No+Image";

  return (
    <div className="item-card">
      <img
        src={previewImage}
        alt={item.title}
      />
      <div className="item-card-content">
        <div className="item-card-header">
          <h3>{item.title}</h3>
          <span className={statusClass}>{item.status}</span>
        </div>
        <p className="item-description">{item.description || "No description provided."}</p>
        <div className="item-metadata">
          <span>Category: {item.category || "-"}</span>
          <span>Location: {item.location || "-"}</span>
          <span>Contact: {item.contactInfo || "-"}</span>
          <span>Reference Images: {parsedImages.length || (item.imageUrl ? 1 : 0)}</span>
        </div>
        <div className="item-actions">
          {canManage ? (
            <>
              <button type="button" onClick={() => onEdit(item)}>Edit</button>
              <button type="button" className="ghost-btn" onClick={() => onDelete(item.id)}>Delete</button>
            </>
          ) : null}
          {item.status === "LOST" ? (
            <button type="button" className="ghost-btn" onClick={() => onReportFound(item)}>
              Report Found
            </button>
          ) : null}
        </div>
      </div>
    </div>
  );
}

export default ItemCard;
